fn test_dlog_m_round_trip() {
        let values = [0.0_f32, 0.1, 0.2, 0.39, 0.5, 0.7, 0.9, 1.0];
        for &v in &values {
            let encoded = linear_to_dlog_m(v);
            let decoded = dlog_m_to_linear(encoded);
            assert!(
                (decoded - v).abs() < 1e-5,
                "Round-trip failed for {v}: got {decoded}"
            );
        }
    }
